def validate(args, output):
    nums, target = args[0], args[1]
    if not isinstance(output, list):
        return False
    from collections import Counter
    avail = Counter(nums)
    seen = set()
    for q in output:
        if not isinstance(q, list) or len(q) != 4:
            return False
        if sum(q) != target:
            return False
        key = tuple(sorted(q))
        if key in seen:
            return False
        seen.add(key)
        c = Counter(q)
        for v, k in c.items():
            if avail.get(v, 0) < k:
                return False
    correct = set()
    s = sorted(nums)
    n = len(s)
    for i in range(n - 3):
        if i > 0 and s[i] == s[i - 1]:
            continue
        for j in range(i + 1, n - 2):
            if j > i + 1 and s[j] == s[j - 1]:
                continue
            l, r = j + 1, n - 1
            while l < r:
                tot = s[i] + s[j] + s[l] + s[r]
                if tot < target:
                    l += 1
                elif tot > target:
                    r -= 1
                else:
                    correct.add((s[i], s[j], s[l], s[r]))
                    l += 1
                    r -= 1
    return seen == correct

