function validate(args, output) {
    const nums = args[0], target = args[1];
    if (!Array.isArray(output)) return false;
    const avail = new Map();
    for (const v of nums) avail.set(v, (avail.get(v) || 0) + 1);
    const seen = new Set();
    for (const q of output) {
        if (!Array.isArray(q) || q.length !== 4) return false;
        if (q[0] + q[1] + q[2] + q[3] !== target) return false;
        const key = [...q].sort((a, b) => a - b).join(',');
        if (seen.has(key)) return false;
        seen.add(key);
        const c = new Map();
        for (const v of q) c.set(v, (c.get(v) || 0) + 1);
        for (const [v, k] of c) if ((avail.get(v) || 0) < k) return false;
    }
    const correct = new Set();
    const s = nums.slice().sort((a, b) => a - b);
    const n = s.length;
    for (let i = 0; i < n - 3; i++) {
        if (i > 0 && s[i] === s[i - 1]) continue;
        for (let j = i + 1; j < n - 2; j++) {
            if (j > i + 1 && s[j] === s[j - 1]) continue;
            let l = j + 1, r = n - 1;
            while (l < r) {
                const tot = s[i] + s[j] + s[l] + s[r];
                if (tot < target) l++;
                else if (tot > target) r--;
                else { correct.add([s[i], s[j], s[l], s[r]].join(',')); l++; r--; }
            }
        }
    }
    if (seen.size !== correct.size) return false;
    for (const k of seen) if (!correct.has(k)) return false;
    return true;
}

