class Solution:
    def fourSum(self, nums, target):
        from itertools import combinations
        s = sorted(nums)
        n = len(s)
        found = set()
        for combo in combinations(range(n), 4):
            a, b, c, d = combo
            if s[a] + s[b] + s[c] + s[d] == target:
                found.add((s[a], s[b], s[c], s[d]))
        return [list(t) for t in sorted(found)]

