    const n = nums.length;
    const res = [];
    for (let i = 0; i < n - 3; i++) {
        if (i > 0 && nums[i] === nums[i - 1]) continue;
        for (let j = i + 1; j < n - 2; j++) {
            if (j > i + 1 && nums[j] === nums[j - 1]) continue;
            let l = j + 1, r = n - 1;
            while (l < r) {
                const tot = nums[i] + nums[j] + nums[l] + nums[r];
                if (tot < target) l++;
                else if (tot > target) r--;
                else {
                    res.push([nums[i], nums[j], nums[l], nums[r]]);
